// Validate case_id — soft fail so n8n doesn't mark polling as error
const item = $input.first().json;
const body = item.body || item;
const caseId = (body.case_id || '').toString().trim();

if (!caseId) {
  // Return soft response — dashboard will handle it
  return [{ json: { found: false, error: 'case_id missing', case_id: null } }];
}

return [{ json: { case_id: caseId } }];

// Format Supabase response for dashboard
// null lawyer fields are NORMAL during polling — not an error
const item = $input.first().json;

// If validate input returned soft error, pass it through
if (item.error) {
  return [{ json: { found: false, error: item.error } }];
}

// Supabase returns array — take first row
const row = Array.isArray(item) ? item[0] : item;

// Case not found in Supabase yet — soft response, not an error
if (!row || !row.case_id) {
  return [{ json: { found: false, case_id: null } }];
}

// Safely parse fields that may be stored as JSON strings in Supabase
function safeParse(val) {
  if (!val) return null;
  if (typeof val === 'object') return val;
  try { return JSON.parse(val); } catch(e) { return null; }
}

// Return full record — null AI fields are fine, dashboard handles them
return [{ json: {
  found: true,

  // Core
  case_id:         row.case_id         || '',
  timestamp:       row.timestamp       || '',
  submitted_by:    row.submitted_by    || '',
  pipeline_status: row.pipeline_status || 'INTAKE_COMPLETE',

  // Client
  user_name:       row.user_name       || '',
  contact_number:  row.contact_number  || '',
  date_of_birth:   row.date_of_birth   || '',
  civil_status:    row.civil_status    || '',
  address:         row.address         || '',
  occupation:      row.occupation      || '',

  // Case details
  legal_topic:     row.legal_topic     || '',
  legal_issue:     row.legal_issue     || '',
  incident_date:   row.incident_date   || '',
  opposing_party:  row.opposing_party  || '',
  urgency:         row.urgency         || '',
  legal_narrative: row.legal_narrative || '',
  clerk_notes:     row.clerk_notes     || '',

  // Documents
  documents_submitted: safeParse(row.documents_submitted) || [],
  attachments_meta:    safeParse(row.attachments_meta)    || [],
  document_urls:       safeParse(row.document_urls)       || [],

  // AI analyses — null is EXPECTED while pipeline is running
  // Dashboard checks for these and renders panels when they arrive
  lawyer_a:       safeParse(row.lawyer_a),
  lawyer_b:       safeParse(row.lawyer_b),
  senior_partner: safeParse(row.senior_partner),
}}];
